"use strict";parserFactory.register("velvet-reverie.org",()=>new VelvetReverieParser);class VelvetReverieParser extends Parser{constructor(){super()}async getChapterUrls(e){let r=e.querySelector("div.story-toc ul");return util.hyperlinksToChapterList(r)}findContent(e){let r=e.querySelector("div.mbs_posts_text"),t=r.querySelectorAll(".jum");for(let e of t)e.remove();return r}extractTitleImpl(e){return e.querySelector("div.story-info-column h1")}extractDescription(e){let r=e.querySelector("div.story-synopsis"),t=r.querySelectorAll(".jum");for(let e of t)e.remove();return r.textContent.trim()}findChapterTitle(e){return e.querySelector("h2.mbs_posts_title")}findCoverImageUrl(e){return e.querySelector("img.story-cover")?.src??null}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.story-synopsis p")]}}